  function copyInvestorMatchMessage(
    lead: Lead,
    item: Listing,
    score: number,
    reasons: string[]
  ) {
    const message = buildInvestorMatchMessage(lead, item, score, reasons);

    try {
      if (navigator.clipboard?.writeText) {
        navigator.clipboard.writeText(message);
      } else {
        const textArea = document.createElement("textarea");
        textArea.value = message;
        textArea.style.position = "fixed";
        textArea.style.left = "-9999px";
        document.body.appendChild(textArea);
        textArea.focus();
        textArea.select();
        document.execCommand("copy");
        document.body.removeChild(textArea);
      }

      addActivityLog(
        "Investor match copied",
        `${item.title} match message copied for ${lead.name}.`,
        "Lead"
      );
      showMessage("Investor match message copied.");
    } catch {
      showMessage("Unable to copy investor match message.");
    }
  }

